{
  "name": "AI Flow Architect",
  "description": "An infinite flow drawing canvas where an intelligent AI agent orchestrates your diagrams through conversation.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Node {
  id: string;
  label: string;
  x: number;
  y: number;
  type: 'process' | 'decision' | 'start' | 'end';
  color?: string;
}

export interface Edge {
  id: string;
  source: string;
  target: string;
  label?: string;
}

export interface CanvasState {
  nodes: Node[];
  edges: Edge[];
}

export interface Message {
  role: 'user' | 'assistant' | 'system';
  content: string;
  isThought?: boolean;
}

export interface Viewport {
  x: number;
  y: number;
  scale: number;
}

export enum ActionID {
  ADD_NODE = 'addNode',
  UPDATE_NODE = 'updateNode',
  DELETE_NODE = 'deleteNode',
  CONNECT_NODES = 'connectNodes',
  CLEAR_CANVAS = 'clearCanvas',
  GET_CANVAS_STATE = 'getCanvasState'
}

import { Type } from "@google/genai";

export const SYSTEM_INSTRUCTION = `
You are a Flow Diagram Architect. Your goal is to help users build and manage complex flowcharts, mind maps, and diagrams on an infinite canvas.

User Interaction Rules:
1. The user CANNOT directly edit the canvas. They only speak to you.
2. You must interpret their intent and use your tools to manipulate the canvas (adding nodes, connecting them, moving them).
3. Always check the current canvas state using 'getCanvasState' before making major structural changes if you're unsure.
4. When adding nodes, try to place them logically (e.g., flow from top to bottom or left to right).
5. Suggest improvements to the diagram structure if it looks messy.

Tool Usage:
- addNode: Creates a new box. Types: 'process', 'decision', 'start', 'end'.
- connectNodes: Draws an arrow between two existing node IDs.
- updateNode: Moves or renames an existing node.
- deleteNode: Removes a node and its associated edges.
- clearCanvas: Wipes everything.

Colors: Use Tailwind-like color names (e.g., 'blue', 'green', 'amber', 'rose').
`;

export const TOOLS = [
  {
    name: 'addNode',
    description: 'Add a new node to the canvas.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        label: { type: Type.STRING, description: 'The text inside the node' },
        x: { type: Type.NUMBER, description: 'X coordinate' },
        y: { type: Type.NUMBER, description: 'Y coordinate' },
        type: { type: Type.STRING, enum: ['process', 'decision', 'start', 'end'], description: 'The shape/type of node' },
        color: { type: Type.STRING, description: 'Background color theme' }
      },
      required: ['label', 'x', 'y']
    }
  },
  {
    name: 'updateNode',
    description: 'Update an existing node.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING, description: 'ID of the node to update' },
        label: { type: Type.STRING },
        x: { type: Type.NUMBER },
        y: { type: Type.NUMBER },
        color: { type: Type.STRING }
      },
      required: ['id']
    }
  },
  {
    name: 'deleteNode',
    description: 'Remove a node and its connections.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING, description: 'ID of the node to delete' }
      },
      required: ['id']
    }
  },
  {
    name: 'connectNodes',
    description: 'Create an edge between two nodes.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        sourceId: { type: Type.STRING, description: 'Starting node ID' },
        targetId: { type: Type.STRING, description: 'Ending node ID' },
        label: { type: Type.STRING, description: 'Optional label for the connection' }
      },
      required: ['sourceId', 'targetId']
    }
  },
  {
    name: 'clearCanvas',
    description: 'Delete all nodes and edges.',
    parameters: { type: Type.OBJECT, properties: {} }
  },
  {
    name: 'getCanvasState',
    description: 'Retrieve the current list of nodes and edges.',
    parameters: { type: Type.OBJECT, properties: {} }
  }
];

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { 
  Plus, 
  Send, 
  Maximize2, 
  Minimize2, 
  Trash2, 
  Download, 
  Upload,
  Brain,
  Layers,
  MousePointer2,
  AlertCircle
} from 'lucide-react';
import { 
  Node, 
  Edge, 
  CanvasState, 
  Message, 
  Viewport, 
  ActionID 
} from './types';
import { SYSTEM_INSTRUCTION, TOOLS } from './constants';
import Canvas from './components/Canvas';

const App: React.FC = () => {
  // --- Canvas State ---
  const [nodes, setNodes] = useState<Node[]>([]);
  const [edges, setEdges] = useState<Edge[]>([]);
  const [viewport, setViewport] = useState<Viewport>({ x: 0, y: 0, scale: 1 });

  // --- UI State ---
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Hello! I am your Flow Architect. Describe the diagram you'd like to build, and I'll handle the drawing for you." }
  ]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentThought, setCurrentThought] = useState<string | null>(null);
  const [history, setHistory] = useState<any[]>([]);

  const chatEndRef = useRef<HTMLDivElement>(null);

  // --- Canvas Methods ---
  const executeAction = useCallback((action: ActionID, args: any) => {
    switch (action) {
      case ActionID.ADD_NODE: {
        const newNode: Node = {
          id: `node-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
          label: args.label || 'New Node',
          x: Number(args.x) || 0,
          y: Number(args.y) || 0,
          type: args.type || 'process',
          color: args.color || 'blue'
        };
        setNodes(prev => [...prev, newNode]);
        return { status: 'success', node: newNode };
      }
      case ActionID.UPDATE_NODE: {
        setNodes(prev => prev.map(n => n.id === args.id ? { ...n, ...args } : n));
        return { status: 'success', id: args.id };
      }
      case ActionID.DELETE_NODE: {
        setNodes(prev => prev.filter(n => n.id !== args.id));
        setEdges(prev => prev.filter(e => e.source !== args.id && e.target !== args.id));
        return { status: 'success', id: args.id };
      }
      case ActionID.CONNECT_NODES: {
        const newEdge: Edge = {
          id: `edge-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
          source: args.sourceId,
          target: args.targetId,
          label: args.label
        };
        setEdges(prev => [...prev, newEdge]);
        return { status: 'success', edge: newEdge };
      }
      case ActionID.CLEAR_CANVAS: {
        setNodes([]);
        setEdges([]);
        return { status: 'success' };
      }
      case ActionID.GET_CANVAS_STATE: {
        return { nodes, edges };
      }
      default:
        throw new Error(`Unknown action: ${action}`);
    }
  }, [nodes, edges]);

  // --- Agent Logic ---
  const sendMessage = async () => {
    if (!userInput.trim() || isProcessing) return;

    const currentInput = userInput;
    setUserInput('');
    setMessages(prev => [...prev, { role: 'user', content: currentInput }]);
    setIsProcessing(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const currentHistory = [...history, { role: 'user', parts: [{ text: currentInput }] }];

    try {
      let loopCount = 0;
      const MAX_LOOPS = 6;

      while (loopCount < MAX_LOOPS) {
        setCurrentThought('Reasoning...');
        const response: any = await ai.models.generateContent({
          model: 'gemini-3-pro-preview',
          contents: currentHistory,
          config: {
            systemInstruction: SYSTEM_INSTRUCTION,
            tools: [{ functionDeclarations: TOOLS }],
          },
        });

        const candidate = response.candidates[0];
        const parts = candidate.content.parts;
        currentHistory.push({ role: 'model', parts });

        const textPart = parts.find((p: any) => p.text);
        const functionCalls = parts.filter((p: any) => p.functionCall).map((p: any) => p.functionCall);

        if (textPart?.text) {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: textPart.text, 
            isThought: functionCalls.length > 0 
          }]);
        }

        if (functionCalls.length === 0) break;

        const toolResponses = [];
        for (const call of functionCalls) {
          setCurrentThought(`Executing: ${call.name}...`);

          let result;
          try {
            result = executeAction(call.name as ActionID, call.args);
          } catch (err: any) {
            result = { error: err.message };
          }

          setMessages(prev => [...prev, { 
            role: 'system', 
            content: `Capability: ${call.name} ${result.error ? '[FAILED]' : '[OK]'}` 
          }]);

          toolResponses.push({
            functionResponse: {
              name: call.name,
              id: call.id,
              response: result
            }
          });
        }

        currentHistory.push({ role: 'user', parts: toolResponses });
        loopCount++;
      }
      setHistory(currentHistory);
    } catch (error: any) {
      setMessages(prev => [...prev, { role: 'assistant', content: `Agent Error: ${error.message}` }]);
    } finally {
      setIsProcessing(false);
      setCurrentThought(null);
    }
  };

  const handleExport = () => {
    const data = JSON.stringify({ nodes, edges, viewport }, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `flow-architecture-${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.nodes && data.edges) {
          setNodes(data.nodes);
          setEdges(data.edges);
          if (data.viewport) setViewport(data.viewport);
        }
      } catch (err) {
        alert('Invalid file format');
      }
    };
    reader.readAsText(file);
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, currentThought]);

  return (
    <div className="flex h-screen w-full bg-slate-900 overflow-hidden font-sans text-slate-200">

      {/* Main Canvas Area */}
      <main className="relative flex-grow h-full bg-slate-950 overflow-hidden">
        {/* Infinite Canvas */}
        <Canvas 
          nodes={nodes} 
          edges={edges} 
          viewport={viewport} 
          setViewport={setViewport} 
        />

        {/* Floating Top Controls */}
        <div className="absolute top-6 left-6 right-6 flex justify-between items-center pointer-events-none">
          <div className="flex items-center space-x-4 pointer-events-auto">
            <div className="bg-slate-800/80 backdrop-blur-md border border-slate-700 p-2 rounded-xl flex space-x-1 shadow-2xl">
              <button 
                onClick={handleExport}
                className="p-2 hover:bg-slate-700 rounded-lg transition-colors group relative"
                title="Export"
              >
                <Download size={20} className="text-slate-400 group-hover:text-white" />
              </button>
              <label className="p-2 hover:bg-slate-700 rounded-lg transition-colors group relative cursor-pointer" title="Import">
                <Upload size={20} className="text-slate-400 group-hover:text-white" />
                <input type="file" className="hidden" onChange={handleImport} accept=".json" />
              </label>
            </div>
            <div className="bg-slate-800/80 backdrop-blur-md border border-slate-700 px-4 py-2 rounded-xl flex items-center space-x-2 shadow-2xl">
              <Layers size={18} className="text-blue-400" />
              <span className="text-sm font-medium text-slate-300">
                {nodes.length} Nodes • {edges.length} Connections
              </span>
            </div>
          </div>
        </div>

        {/* Viewport Hint */}
        <div className="absolute bottom-6 left-6 bg-slate-800/80 backdrop-blur-md border border-slate-700 px-3 py-1.5 rounded-lg pointer-events-none flex items-center space-x-2 text-xs text-slate-400 shadow-lg">
          <MousePointer2 size={12} />
          <span>Space + Drag to Pan • Scroll to Zoom</span>
        </div>
      </main>

      {/* Sidebar AI Agent */}
      <aside 
        className={`transition-all duration-500 ease-in-out bg-slate-800 border-l border-slate-700 flex flex-col relative z-50 shadow-2xl ${
          isExpanded ? 'fixed inset-0 w-full' : 'w-[450px]'
        }`}
      >
        {/* Sidebar Header */}
        <div className="p-4 border-b border-slate-700 flex justify-between items-center bg-slate-800/50">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 rounded-xl bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-900/20">
              <Brain size={24} className="text-white" />
            </div>
            <div>
              <h2 className="font-bold text-slate-100">Flow Architect</h2>
              <p className="text-xs text-slate-400 flex items-center space-x-1">
                <span className={`w-2 h-2 rounded-full ${isProcessing ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`}></span>
                <span>{isProcessing ? 'Thinking...' : 'Ready to help'}</span>
              </p>
            </div>
          </div>
          <div className="flex space-x-2">
             <button 
              onClick={() => setIsExpanded(!isExpanded)}
              className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors"
            >
              {isExpanded ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
            </button>
          </div>
        </div>

        {/* Chat History */}
        <div className="flex-grow overflow-y-auto p-6 space-y-6 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
          {messages.map((msg, idx) => (
            <div 
              key={idx} 
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              <div className={`max-w-[85%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : msg.role === 'system'
                    ? 'bg-slate-700/50 text-slate-400 text-xs italic font-mono border border-slate-700/50'
                    : 'bg-slate-700 text-slate-200 rounded-tl-none border border-slate-600'
              }`}>
                {msg.role === 'assistant' && msg.isThought && (
                  <div className="flex items-center space-x-2 mb-2 text-xs font-semibold text-blue-400 uppercase tracking-wider">
                    <Brain size={12} />
                    <span>Planning Canvas Operations</span>
                  </div>
                )}
                <div className="whitespace-pre-wrap leading-relaxed">{msg.content}</div>
              </div>
            </div>
          ))}
          {currentThought && (
            <div className="flex justify-start">
              <div className="bg-slate-700 text-slate-400 text-xs p-3 rounded-xl rounded-tl-none flex items-center space-x-3 border border-slate-600 animate-pulse">
                <div className="w-2 h-2 bg-blue-400 rounded-full animate-ping"></div>
                <span>{currentThought}</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-6 border-t border-slate-700 bg-slate-800/50">
          <div className="relative group">
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage();
                }
              }}
              placeholder="Tell me what to draw... (e.g. 'Create a sign-up flow starting at 100,100')"
              className="w-full bg-slate-900 border border-slate-700 rounded-2xl py-4 pl-4 pr-16 focus:outline-none focus:ring-2 focus:ring-blue-500/50 focus:border-blue-500 transition-all text-slate-200 placeholder-slate-500 resize-none min-h-[100px]"
            />
            <button
              onClick={sendMessage}
              disabled={isProcessing || !userInput.trim()}
              className={`absolute bottom-4 right-4 p-3 rounded-xl transition-all shadow-lg ${
                isProcessing || !userInput.trim()
                  ? 'bg-slate-800 text-slate-600'
                  : 'bg-blue-600 text-white hover:bg-blue-500 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} />
            </button>
          </div>
          <p className="mt-3 text-center text-xs text-slate-500">
            Powered by Gemini • Commands are executed via Tool Calling
          </p>
        </div>
      </aside>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { Node, Edge, Viewport } from '../types';

interface CanvasProps {
  nodes: Node[];
  edges: Edge[];
  viewport: Viewport;
  setViewport: React.Dispatch<React.SetStateAction<Viewport>>;
}

const Canvas: React.FC<CanvasProps> = ({ nodes, edges, viewport, setViewport }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isPanning, setIsPanning] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const scaleFactor = 1.1;
    const newScale = e.deltaY < 0 ? viewport.scale * scaleFactor : viewport.scale / scaleFactor;
    const clampedScale = Math.min(Math.max(newScale, 0.1), 5);

    // Zoom toward mouse position
    if (containerRef.current) {
        const rect = containerRef.current.getBoundingClientRect();
        const mouseX = e.clientX - rect.left;
        const mouseY = e.clientY - rect.top;

        // Calculate world position before zoom
        const worldX = (mouseX - viewport.x) / viewport.scale;
        const worldY = (mouseY - viewport.y) / viewport.scale;

        // New viewport after zoom to keep world position under mouse
        const newX = mouseX - worldX * clampedScale;
        const newY = mouseY - worldY * clampedScale;

        setViewport({ x: newX, y: newY, scale: clampedScale });
    }
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    // Only pan if space bar is held or middle mouse button
    if (e.button === 1 || (e.button === 0 && e.shiftKey)) {
        setIsPanning(true);
        setLastMousePos({ x: e.clientX, y: e.clientY });
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isPanning) {
      const dx = e.clientX - lastMousePos.x;
      const dy = e.clientY - lastMousePos.y;
      setViewport(prev => ({ ...prev, x: prev.x + dx, y: prev.y + dy }));
      setLastMousePos({ x: e.clientX, y: e.clientY });
    }
  };

  const handleMouseUp = () => {
    setIsPanning(false);
  };

  // Color mapping for nodes
  const getColorClasses = (color?: string) => {
    switch (color) {
      case 'amber': return 'bg-amber-900/40 border-amber-500 text-amber-100 shadow-amber-500/10';
      case 'green': return 'bg-emerald-900/40 border-emerald-500 text-emerald-100 shadow-emerald-500/10';
      case 'rose': return 'bg-rose-900/40 border-rose-500 text-rose-100 shadow-rose-500/10';
      case 'purple': return 'bg-purple-900/40 border-purple-500 text-purple-100 shadow-purple-500/10';
      default: return 'bg-blue-900/40 border-blue-500 text-blue-100 shadow-blue-500/10';
    }
  };

  const getNodeShape = (type: Node['type']) => {
    switch (type) {
      case 'decision': return 'rotate-45 p-6 aspect-square flex items-center justify-center';
      case 'start':
      case 'end': return 'rounded-full px-6 py-2';
      default: return 'rounded-xl px-5 py-4 min-w-[140px]';
    }
  };

  return (
    <div 
      ref={containerRef}
      className={`w-full h-full relative overflow-hidden bg-slate-950 canvas-grid cursor-grab ${isPanning ? 'cursor-grabbing' : ''}`}
      onWheel={handleWheel}
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      <div 
        className="absolute top-0 left-0 origin-top-left transition-transform duration-75 ease-out"
        style={{ 
          transform: `translate(${viewport.x}px, ${viewport.y}px) scale(${viewport.scale})` 
        }}
      >
        {/* SVG layer for Edges */}
        <svg className="absolute top-0 left-0 w-full h-full pointer-events-none overflow-visible">
          <defs>
            <marker
              id="arrowhead"
              markerWidth="10"
              markerHeight="7"
              refX="10"
              refY="3.5"
              orient="auto"
            >
              <polygon points="0 0, 10 3.5, 0 7" fill="#64748b" />
            </marker>
          </defs>
          {edges.map(edge => {
            const source = nodes.find(n => n.id === edge.source);
            const target = nodes.find(n => n.id === edge.target);
            if (!source || !target) return null;

            // Simple line path logic
            const x1 = source.x;
            const y1 = source.y;
            const x2 = target.x;
            const y2 = target.y;

            return (
              <g key={edge.id}>
                <path
                  d={`M ${x1} ${y1} L ${x2} ${y2}`}
                  stroke="#64748b"
                  strokeWidth="2"
                  fill="none"
                  markerEnd="url(#arrowhead)"
                  className="transition-all"
                />
                {edge.label && (
                  <text
                    x={(x1 + x2) / 2}
                    y={(y1 + y2) / 2 - 10}
                    fill="#94a3b8"
                    fontSize="10"
                    textAnchor="middle"
                    className="select-none font-medium"
                  >
                    {edge.label}
                  </text>
                )}
              </g>
            );
          })}
        </svg>

        {/* DOM layer for Nodes */}
        {nodes.map(node => (
          <div
            key={node.id}
            className={`absolute border-2 shadow-2xl transition-all duration-300 transform -translate-x-1/2 -translate-y-1/2 ${getColorClasses(node.color)} ${getNodeShape(node.type)}`}
            style={{ left: node.x, top: node.y }}
          >
            <div className={`text-center font-semibold select-none whitespace-nowrap ${node.type === 'decision' ? '-rotate-45' : ''}`}>
              {node.label}
            </div>
            {/* Subtle ID indicator */}
            <div className={`absolute -bottom-6 left-1/2 -translate-x-1/2 text-[10px] text-slate-500 font-mono tracking-tighter ${node.type === 'decision' ? '-rotate-45 bottom-[-20px]' : ''}`}>
              {node.id.split('-')[0]}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

