import { ZAI } from 'zai-sdk';
import { useState } from 'react';

type Message = {
  role: 'user' | 'assistant' | 'system';
  content: string;
  isThought?: boolean;
};

export function DrawingAgent() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [currentThought, setCurrentThought] = useState<string | null>(null);
  const [userInput, setUserInput] = useState('');

  const client = new ZAI({ apiKey: process.env.NEXT_PUBLIC_ZAI_API_KEY });

  const SYSTEM_INSTRUCTION =
    'You are an expert drawing assistant. Help users create drawings.';

  const TOOLS = [
    {
      type: 'function' as const,
      function: {
        name: 'draw_circle',
        description: 'Draw a circle',
        parameters: {
          type: 'object',
          properties: {
            x: { type: 'number' },
            y: { type: 'number' },
            radius: { type: 'number' },
            color: { type: 'string' },
          },
          required: ['x', 'y', 'radius'],
        },
      },
    },
  ];

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (!userInput.trim()) return;

    setIsProcessing(true);
    setMessages((prev) => [...prev, { role: 'user', content: userInput }]);

    try {
      let conversationHistory: Array<{ role: string; content: string }> = [];

      for (let loop = 0; loop < 10; loop++) {
        setCurrentThought('Reasoning...');

        const chatMessages = [
          {
            role: 'user' as const,
            content:
              loop === 0
                ? `${SYSTEM_INSTRUCTION}\n\nUser request: ${userInput}`
                : conversationHistory[conversationHistory.length - 1].content,
          },
          ...conversationHistory.slice(0, -1),
        ];

        const response = await client.chat.create({
          model: 'glm-4-7',
          messages: chatMessages,
          tools: TOOLS,
        });

        const message = response.choices.message;
        const toolCalls = message.tool_calls || [];
        const textContent = message.content || '';

        conversationHistory.push({ role: 'assistant', content: textContent });

        if (textContent) {
          setMessages((prev) => [
            ...prev,
            {
              role: 'assistant',
              content: textContent,
              isThought: toolCalls.length > 0,
            },
          ]);
        }

        if (toolCalls.length === 0) break;

        for (const call of toolCalls) {
          setCurrentThought(`Executing: ${call.function.name}...`);

          let result;
          try {
            const args = JSON.parse(call.function.arguments);
            result = executeAction(call.function.name, args);
          } catch (err: any) {
            result = { error: err.message };
          }

          setMessages((prev) => [
            ...prev,
            {
              role: 'system',
              content: `Tool result: ${
                result.error ? `[FAILED] ${result.error}` : '[OK]'
              }`,
            },
          ]);

          conversationHistory.push({
            role: 'tool',
            content: JSON.stringify(result),
          });
        }
      }
    } catch (error: any) {
      setMessages((prev) => [
        ...prev,
        { role: 'assistant', content: `Error: ${error.message}` },
      ]);
    } finally {
      setIsProcessing(false);
      setCurrentThought(null);
      setUserInput('');
    }
  }

  function executeAction(name: string, args: any) {
    // 實現你的工具邏輯
    return { success: true };
  }

  return (
    <div>
      {messages.map((msg, i) => (
        <div key={i} className={msg.role}>
          {msg.content}
        </div>
      ))}
      {currentThought && <div className="thinking">{currentThought}</div>}
      <form onSubmit={handleSubmit}>
        <input
          value={userInput}
          onChange={(e) => setUserInput(e.target.value)}
          disabled={isProcessing}
        />
        <button type="submit" disabled={isProcessing}>
          {isProcessing ? 'Processing...' : 'Send'}
        </button>
      </form>
    </div>
  );
}

