export enum ActionID {
  ADD_NODE = 'addNode',
  UPDATE_NODE = 'updateNode',
  DELETE_NODE = 'deleteNode',
  CONNECT_NODES = 'connectNodes',
  CLEAR_CANVAS = 'clearCanvas',
  GET_CANVAS_STATE = 'getCanvasState'
}

import { Type } from "@google/genai";

export const SYSTEM_INSTRUCTION = `
You are a UX Architect and Prototyper. Your goal is to help users build UI flows and wireframes on an infinite canvas.

New Capability: UX Prototyping
- You can now lay down functional UI components on the canvas.
- To add a UI component, use 'addNode' with type='ux'.
- Supported 'componentType' values:
  * 'login-form': A standard authentication form.

User Interaction Rules:
1. The user speaks to you to describe their app flow or UI needs.
2. Interpret intent: "I need a login page connected to a dashboard" -> Add a 'login-form' UX node and a 'process' node for the dashboard, then connect them.
3. Coordinates: UI components are larger than standard nodes. 
   - 'login-form' size is roughly 350x450px. Use spacing of ~500px between nodes.
4. Always use IDs for connections, never labels.

Colors: Use Tailwind color names for theme hints.
`;

export const TOOLS = [
  {
    name: 'addNode',
    description: 'Add a new node or UX component to the canvas.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        label: { type: Type.STRING, description: 'The title/label for the node' },
        x: { type: Type.NUMBER, description: 'X coordinate' },
        y: { type: Type.NUMBER, description: 'Y coordinate' },
        type: { type: Type.STRING, enum: ['process', 'decision', 'start', 'end', 'ux'], description: 'The type of node' },
        componentType: { type: Type.STRING, enum: ['login-form'], description: 'If type is ux, specify which component to render' },
        color: { type: Type.STRING, description: 'Theme color' }
      },
      required: ['label', 'x', 'y']
    }
  },
  {
    name: 'updateNode',
    description: 'Update an existing node.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING, description: 'ID of the node to update' },
        label: { type: Type.STRING },
        x: { type: Type.NUMBER },
        y: { type: Type.NUMBER },
        color: { type: Type.STRING }
      },
      required: ['id']
    }
  },
  {
    name: 'deleteNode',
    description: 'Remove a node and its connections.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        id: { type: Type.STRING, description: 'ID of the node to delete' }
      },
      required: ['id']
    }
  },
  {
    name: 'connectNodes',
    description: 'Create an edge between two nodes.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        sourceId: { type: Type.STRING, description: 'Starting node ID' },
        targetId: { type: Type.STRING, description: 'Ending node ID' },
        label: { type: Type.STRING, description: 'Optional label for the connection' }
      },
      required: ['sourceId', 'targetId']
    }
  },
  {
    name: 'clearCanvas',
    description: 'Delete all nodes and edges.',
    parameters: { type: Type.OBJECT, properties: {} }
  },
  {
    name: 'getCanvasState',
    description: 'Retrieve the current list of nodes and edges including all IDs.',
    parameters: { type: Type.OBJECT, properties: {} }
  }
];

