  nodes: any[];
  edges: any[];
  onNodesChange: any;
  onEdgesChange: any;
}

const Canvas: React.FC<CanvasProps> = ({ nodes, edges, onNodesChange, onEdgesChange }) => {
  const nodeTypes = useMemo(() => ({
    default: CustomNode,
    process: CustomNode,
    start: CustomNode,
    end: CustomNode,
    diamond: DiamondNode,
    ux: UXNode,
  }), []);

  return (
    <div className="w-full h-full">
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        nodeTypes={nodeTypes}
        nodesDraggable={true}
        nodesConnectable={true}
        elementsSelectable={true}
        fitView
        colorMode="dark"
        minZoom={0.1}
        maxZoom={4}
      >
        <Background 
            variant={BackgroundVariant.Dots} 
            gap={20} 
            size={1} 
