// UX Node Component for rich UI elements
const UXNode = ({ id, data, selected }: any) => {
  const Component = UX_COMPONENTS[data.componentType];

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (data.executeAction) {
      data.executeAction(CapabilityUpdateComponentType.id, {
        id,
        componentType: e.target.value
      });
    }
  };

  return (
    <div className={`relative ${selected ? 'ring-2 ring-blue-500 rounded-2xl ring-offset-4 ring-offset-slate-950' : ''}`}>
      <div className="absolute -top-10 left-0 flex items-center space-x-2 w-full">
