// UX Node Component for rich UI elements
const UXNode = ({ id, data, selected }: any) => {
  const Component = UX_COMPONENTS[data.componentType];

  const handleTypeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    if (data.executeAction) {
      data.executeAction(CapabilityUpdateComponentType.id, {
        id,
        componentType: e.target.value
      });
    }
  };

  return (
    <div className={`relative ${selected ? 'ring-2 ring-blue-500 rounded-2xl ring-offset-4 ring-offset-slate-950' : ''}`}>
      <div className="absolute -top-10 left-0 flex items-center space-x-2 w-full">
        <select 
          value={data.componentType}
          onChange={handleTypeChange}
          className="bg-blue-600 text-[10px] font-bold text-white uppercase tracking-wider rounded shadow-lg px-2 py-1 outline-none border-none cursor-pointer hover:bg-blue-500 transition-colors"
        >
          {Object.keys(UX_COMPONENTS).map(type => (
            <option key={type} value={type}>{type}</option>
          ))}
        </select>
        <span className="text-[10px] font-medium text-slate-500 truncate max-w-[120px] bg-slate-900/50 px-2 py-1 rounded">
          {data.label}
        </span>
      </div>

      <Handle type="target" position={Position.Left} className="!bg-blue-500 !w-2.5 !h-2.5 !border-slate-900" />

      <div className="cursor-default">
        {Component ? <Component {...data.componentProps} /> : (
          <div className="p-4 bg-slate-800 rounded-lg text-slate-400 italic border border-slate-700 w-[200px]">
            Component '{data.componentType}' not found in registry
          </div>
        )}
      </div>

      <Handle type="source" position={Position.Right} className="!bg-blue-500 !w-2.5 !h-2.5 !border-slate-900" />
    </div>
  );
};

interface CanvasProps {
  nodes: any[];
  edges: any[];
  onNodesChange: any;
  onEdgesChange: any;
}

const Canvas: React.FC<CanvasProps> = ({ nodes, edges, onNodesChange, onEdgesChange }) => {
  const nodeTypes = useMemo(() => ({
    default: CustomNode,
    process: CustomNode,
    start: CustomNode,
    end: CustomNode,
    diamond: DiamondNode,
    ux: UXNode,
  }), []);

  return (
    <div className="w-full h-full">
      <ReactFlow
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        nodeTypes={nodeTypes}
        nodesDraggable={true}
        nodesConnectable={true}
        elementsSelectable={true}
        fitView
        colorMode="dark"
        minZoom={0.1}
        maxZoom={4}
      >
        <Background 
            variant={BackgroundVariant.Dots} 
            gap={20} 
            size={1} 
            color="#334155" 
            style={{ backgroundColor: '#020617' }} 
        />
        <Controls />
        <MiniMap 
            nodeColor={(n: any) => n.data?.color || '#3b82f6'} 
            maskColor="rgba(2, 6, 23, 0.7)" 
            style={{ bottom: 20, right: 20 }}
        />
        <Panel position="top-right" className="bg-slate-900/50 backdrop-blur-md p-2 rounded-lg border border-slate-800 text-[10px] text-slate-500 font-mono pointer-events-none">
          ARCHITECT ENGINE: v3.1-CAPABILITY-UI
        </Panel>
      </ReactFlow>
    </div>
  );
};

export default Canvas;

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { 
  ReactFlow, 
  Background, 
  Controls, 
  MiniMap, 
  BackgroundVariant,
  Panel,
  Handle,
  Position
} from '@xyflow/react';
import { Search, ChevronDown, Check } from 'lucide-react';
import { UX_COMPONENTS } from './ux/registry';
import { CapabilityUpdateComponentType } from '../capabilities/index';

// Custom Node Component for flowchart steps
const CustomNode = ({ data, selected }: any) => {
  return (
