// Autocomplete Component for UX nodes
const ComponentAutocomplete = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  const options = Object.keys(UX_COMPONENTS);
  const filteredOptions = options.filter(opt => 
    opt.toLowerCase().includes(query.toLowerCase())
  );

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div ref={containerRef} className="relative w-48 group">
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center justify-between bg-blue-600 hover:bg-blue-500 text-white px-3 py-1.5 rounded-lg shadow-lg cursor-pointer transition-all border border-blue-400/30"
      >
        <span className="text-[10px] font-bold uppercase tracking-wider truncate mr-2">
          {value || 'Select Component'}
        </span>
        <ChevronDown size={14} className={`transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} />
      </div>

      {isOpen && (
        <div className="absolute top-full left-0 mt-2 w-full bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-[100] overflow-hidden animate-in fade-in slide-in-from-top-2 duration-200">
