            <Search size={12} className="text-slate-500 mr-2" />
            <input 
              autoFocus
              className="bg-transparent border-none outline-none text-[10px] text-slate-200 w-full placeholder-slate-600"
              placeholder="Search components..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onClick={(e) => e.stopPropagation()}
            />
          </div>
          <div className="max-h-48 overflow-y-auto p-1 custom-scrollbar">
            {filteredOptions.length > 0 ? (
              filteredOptions.map((opt) => (
                <div 
                  key={opt}
                  onClick={(e) => {
                    e.stopPropagation();
                    onChange(opt);
                    setIsOpen(false);
                    setQuery('');
                  }}
                  className={`flex items-center justify-between px-3 py-2 rounded-lg text-[10px] font-medium cursor-pointer transition-colors ${
                    value === opt 
                      ? 'bg-blue-600/20 text-blue-400' 
                      : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                  }`}
                >
                  <span>{opt}</span>
                  {value === opt && <Check size={10} />}
                </div>
              ))
            ) : (
              <div className="px-3 py-4 text-[10px] text-slate-600 italic text-center">
                No components found
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

