// UX Node Component for rich UI elements
const UXNode = ({ id, data, selected }: any) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [viewMode, setViewMode] = useState<'desktop' | 'mobile'>('desktop');
  const Component = UX_COMPONENTS[data.componentType];

  const handleTypeChange = (newType: string) => {
    if (data.executeAction) {
      data.executeAction(CapabilityUpdateComponentType.id, {
        id,
        componentType: newType
      });
    }
  };

  const previewWidth = 280;
  const previewHeight = 350;

  // Render the modal into the body to avoid canvas clipping
  const Modal = () => {
    if (!isModalOpen) return null;
    return createPortal(
      <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-slate-950/80 backdrop-blur-sm animate-in fade-in duration-300">
        <div className="relative w-[90vw] h-[90vh] bg-slate-900 border border-slate-800 rounded-3xl shadow-3xl flex flex-col overflow-hidden">
          {/* Modal Header */}
          <div className="p-4 border-b border-slate-800 flex items-center justify-between bg-slate-900/50">
            <div className="flex items-center space-x-4">
              <div className="flex flex-col">
                <h3 className="text-sm font-bold text-white uppercase tracking-widest">{data.componentType}</h3>
                <span className="text-[10px] text-slate-500 font-mono">{id}</span>
              </div>
              <div className="h-6 w-[1px] bg-slate-800 mx-2" />
              <div className="flex bg-slate-950 p-1 rounded-xl border border-slate-800">
                <button 
                  onClick={() => setViewMode('desktop')}
                  className={`px-3 py-1.5 rounded-lg flex items-center space-x-2 transition-all ${viewMode === 'desktop' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  <Monitor size={14} />
                  <span className="text-[10px] font-bold">Desktop</span>
                </button>
                <button 
                  onClick={() => setViewMode('mobile')}
                  className={`px-3 py-1.5 rounded-lg flex items-center space-x-2 transition-all ${viewMode === 'mobile' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-300'}`}
                >
                  <Smartphone size={14} />
                  <span className="text-[10px] font-bold">Mobile</span>
                </button>
              </div>
            </div>
            <button 
              onClick={() => setIsModalOpen(false)}
              className="p-2 hover:bg-slate-800 rounded-full transition-all text-slate-400 hover:text-white"
            >
              <X size={24} />
            </button>
          </div>

          {/* Modal Content */}
          <div className="flex-grow bg-slate-950 p-8 flex items-center justify-center overflow-auto pattern-grid">
            <div className={`transition-all duration-500 ease-in-out border border-slate-800 shadow-2xl rounded-xl overflow-hidden bg-white ${viewMode === 'mobile' ? 'w-[375px] h-[667px]' : 'w-full max-w-[1200px] h-full max-h-[800px]'}`}>
              {Component ? <Component {...data.componentProps} /> : <div className="p-10 text-slate-400 italic">Component not found</div>}
            </div>
          </div>
        </div>
      </div>,
      document.body
    );
  };

  return (
    <div className={`relative group transition-all duration-300 ${selected ? 'ring-4 ring-blue-500/50 rounded-3xl' : ''}`}>
      {/* Top UI Overlay */}
      <div className="absolute -top-14 left-0 flex items-center justify-between w-full px-1">
        <ComponentAutocomplete 
          value={data.componentType}
          onChange={handleTypeChange}
        />
        <div className="flex space-x-2 pointer-events-auto">
           <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-slate-900/90 backdrop-blur-md border border-slate-700 p-2 rounded-lg text-slate-400 hover:text-white hover:border-blue-500 transition-all shadow-xl"
            title="Expand Preview"
          >
            <Maximize2 size={16} />
          </button>
        </div>
      </div>

      <Handle type="target" position={Position.Left} className="!bg-blue-500 !w-3 !h-3 !border-slate-900 !-left-1.5" />

      {/* Fixed Container Preview */}
      <div 
        className="relative bg-slate-900 rounded-2xl overflow-hidden border-2 border-slate-800 shadow-2xl transition-all group-hover:border-slate-700"
        style={{ width: previewWidth, height: previewHeight }}
      >
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none origin-center" style={{ transform: 'scale(0.7)' }}>
          {Component ? (
             <div className="pointer-events-none scale-90">
                <Component {...data.componentProps} />
             </div>
          ) : (
            <div className="p-4 text-slate-600 italic text-xs">Component not found</div>
          )}
        </div>

        {/* Interaction blocker for canvas dragging */}
        <div className="absolute inset-0 bg-transparent z-10" />

        {/* Floating Quick Action */}
        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity z-20 pointer-events-none">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsModalOpen(true); }}
            className="pointer-events-auto bg-blue-600 hover:bg-blue-500 text-white px-4 py-2 rounded-full shadow-2xl font-bold text-[10px] uppercase tracking-widest flex items-center space-x-2 transform translate-y-4 group-hover:translate-y-0 transition-all"
          >
            <ExternalLink size={12} />
            <span>Open Prototype</span>
          </button>
        </div>
      </div>

      <Handle type="source" position={Position.Right} className="!bg-blue-500 !w-3 !h-3 !border-slate-900 !-right-1.5" />

      {/* Label and ID Footer */}
      <div className="mt-2 flex items-center justify-between px-2">
        <span className="text-[10px] font-bold text-slate-500 truncate max-w-[120px]">{data.label}</span>
        <span className="text-[9px] font-mono text-slate-700">{id}</span>
      </div>

      <Modal />
    </div>
  );
};

