export const UXNode = ({ id, data, selected }: any) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [scale, setScale] = useState(0.5);
  const componentRef = useRef<HTMLDivElement>(null);
  const Component = UX_COMPONENTS[data.componentType];

  // Fixed preview container dimensions
  const previewWidth = 260;
  const previewHeight = 320;

  // Internal margin for the component within the container
  // Increased to 40 to ensure a clear "tiny bit" of margin (20px on each side)
  const paddingBuffer = 40;

  // Calculate the scale to fit the component perfectly into the preview area with consistent margin
  useLayoutEffect(() => {
    if (componentRef.current) {
      const { scrollWidth, scrollHeight } = componentRef.current;
      if (scrollWidth > 0 && scrollHeight > 0) {
        // We use Math.min to ensure the component is contained entirely by the smaller dimension
        const scaleW = (previewWidth - paddingBuffer) / scrollWidth;
        const scaleH = (previewHeight - paddingBuffer) / scrollHeight;
        setScale(Math.min(scaleW, scaleH));
      }
    }
  }, [data.componentType, data.componentProps, previewWidth, previewHeight]);

  const handleTypeChange = (newType: string) => {
    if (data.executeAction) {
      data.executeAction(CapabilityUpdateComponentType.id, {
        id,
        componentType: newType
      });
