  };

  return (
    <div className={`relative group transition-all duration-300 ${selected ? 'ring-4 ring-blue-500/50 rounded-2xl' : ''}`}>
      {/* Top UI Overlay */}
      <div className="absolute -top-10 left-0 flex items-center justify-between w-full px-0">
