import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { useNodesState, useEdgesState, addEdge, MarkerType, Connection } from '@xyflow/react';
import { 
  Send, 
  Maximize2, 
  Minimize2, 
  Download, 
  Upload,
  Brain,
  Layers,
  Plus,
  Layout
} from 'lucide-react';
import { 
  Message
} from './types';
import { 
  CapabilityAddNode, 
  CapabilityUpdateNode, 
  CapabilityUpdateComponentType,
  CapabilityDeleteNode, 
  CapabilityConnectNodes, 
  CapabilityClearCanvas, 
  CapabilityGetCanvasState,
  CapabilityAddTrack
} from './capabilities';
import { SYSTEM_INSTRUCTION, TOOLS } from './constants';
import Canvas from './components/Canvas';

const App: React.FC = () => {
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  const nodesRef = useRef(nodes);
  const edgesRef = useRef(edges);
  useEffect(() => { nodesRef.current = nodes; }, [nodes]);
  useEffect(() => { edgesRef.current = edges; }, [edges]);

  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "Hello! I am your UX Prototyper. I use an architectural foundation to organize UI flows. You can add tracks and attach components to them. How can I help you build?" }
  ]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentThought, setCurrentThought] = useState<string | null>(null);
  const [history, setHistory] = useState<any[]>([]);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const getHexColor = (color: string = 'blue') => {
    const palette: Record<string, string> = {
      blue: '#3b82f6',
      green: '#10b981',
      amber: '#f59e0b',
      rose: '#f43f5e',
      purple: '#a855f7',
      slate: '#64748b',
      indigo: '#6366f1'
    };
    return palette[color] || palette.blue;
  };

  const executeAction = useCallback((actionId: string, args: any, isManual: boolean = false) => {
    let result: any;

    switch (actionId) {
      case CapabilityAddTrack.id: {
        const id = `track-${Date.now()}`;
        const newNode = {
          id,
          type: 'track',
          position: { x: args.x ?? 0, y: args.y ?? 0 },
          data: { 
            label: args.label || 'System Foundation',
            width: args.width || 2000,
            color: getHexColor(args.color || 'indigo'),
            executeAction: (id: string, args: any) => executeAction(id, args, true)
          },
        };
        setNodes((nds) => {
          const updated = nds.concat(newNode);
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id };
        break;
      }

      case CapabilityAddNode.id: {
        const id = `node-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

        let finalX = args.x ?? 100;
        let finalY = args.y ?? 100;
        let onTrack = false;

        // Handle Track Positioning
        if (args.trackId) {
          const trackNode = nodesRef.current.find(n => n.id === args.trackId);
          if (trackNode) {
            const slot = args.slot ?? 0;
            const slotWidth = 450; // Horizontal spacing between UX nodes on track
            finalX = trackNode.position.x + (slot * slotWidth) + 100; // Offset from start of track
            finalY = trackNode.position.y - 420; // Sit 420px above the track (stem height + node height)
            onTrack = true;
          }
        }

        const newNode = {
          id,
          type: args.type === 'ux' ? 'ux' : (args.type === 'decision' ? 'diamond' : args.type || 'default'),
          position: { x: finalX, y: finalY },
          data: { 
            label: args.label || 'New Step',
            color: getHexColor(args.color),
            componentType: args.componentType,
            onTrack,
            executeAction: (id: string, args: any) => executeAction(id, args, true)
          },
        };
        setNodes((nds) => {
          const updated = nds.concat(newNode);
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id };
        break;
      }

      case CapabilityUpdateNode.id: {
        setNodes((nds) => {
          const updated = nds.map((node) => {
            if (node.id === args.id) {
              return {
                ...node,
                position: args.x !== undefined || args.y !== undefined 
                  ? { x: args.x ?? node.position.x, y: args.y ?? node.position.y }
                  : node.position,
                data: { 
                  ...node.data, 
                  label: args.label ?? node.data.label,
                  color: args.color ? getHexColor(args.color) : node.data.color
                }
              };
            }
            return node;
          });
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityUpdateComponentType.id: {
        setNodes((nds) => {
          const updated = nds.map((node) => {
            if (node.id === args.id) {
              return {
                ...node,
                data: { 
                  ...node.data, 
                  componentType: args.componentType
                }
              };
            }
            return node;
          });
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityDeleteNode.id: {
        setNodes((nds) => {
          const updated = nds.filter((n) => n.id !== args.id);
          nodesRef.current = updated;
          return updated;
        });
        setEdges((eds) => {
          const updated = eds.filter((e) => e.source !== args.id && e.target !== args.id);
          edgesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityConnectNodes.id: {
        const edgeId = `edge-${args.sourceId}-${args.targetId}`;
        const newEdge = {
          id: edgeId,
          source: args.sourceId,
          target: args.targetId,
          label: args.label,
          animated: true,
          style: { stroke: '#6366f1', strokeWidth: 2 },
          markerEnd: { type: MarkerType.ArrowClosed, color: '#6366f1' },
        };
        setEdges((eds) => {
          const updated = addEdge(newEdge, eds);
          edgesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: edgeId };
        break;
      }

      case CapabilityClearCanvas.id: {
        setNodes([]);
        setEdges([]);
        nodesRef.current = [];
        edgesRef.current = [];
        result = { status: 'success' };
        break;
      }

      case CapabilityGetCanvasState.id: {
        result = { nodes: nodesRef.current, edges: edgesRef.current };
        break;
      }

      default:
        throw new Error(`Capability Exception: Unknown Action ID "${actionId}"`);
    }

    if (isManual) {
      setMessages(prev => [...prev, { 
        role: 'system', 
        content: `Manual Capability Audit: ${actionId} executed successfully.` 
      }]);
    }

    return result;
  }, [setNodes, setEdges]);

  useEffect(() => {
    setNodes((nds) => nds.map(n => ({
      ...n,
      data: { ...n.data, executeAction }
    })));
  }, [executeAction]);

  const onConnect = useCallback((params: Connection) => {
    executeAction(CapabilityConnectNodes.id, {
      sourceId: params.source,
      targetId: params.target
    }, true);
  }, [executeAction]);

  const sendMessage = async () => {
    if (!userInput.trim() || isProcessing) return;

    const currentInput = userInput;
    setUserInput('');
    setMessages(prev => [...prev, { role: 'user', content: currentInput }]);
    setIsProcessing(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const currentHistory = [...history, { role: 'user', parts: [{ text: currentInput }] }];

    try {
      let loopCount = 0;
      const MAX_LOOPS = 6;

      while (loopCount < MAX_LOOPS) {
        setCurrentThought('Reasoning Architectural Alignment...');
        const response: GenerateContentResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: currentHistory,
          config: {
            systemInstruction: SYSTEM_INSTRUCTION,
            tools: [{ functionDeclarations: TOOLS as any }],
          },
        });

        const candidate = response.candidates?.[0];
        if (!candidate) break;

        const parts = candidate.content.parts;
        currentHistory.push({ role: 'model', parts });

        const textOutput = response.text;
        const functionCalls = response.functionCalls || [];

        if (textOutput) {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: textOutput, 
            isThought: functionCalls.length > 0 
          }]);
        }

        if (functionCalls.length === 0) break;

        const toolResponses = [];
        for (const call of functionCalls) {
          setCurrentThought(`Executing System Capability: ${call.name}...`);

          let result;
          try {
            result = executeAction(call.name, call.args);
          } catch (err: any) {
            result = { error: err.message };
          }

          setMessages(prev => [...prev, { 
            role: 'system', 
            content: `Audit: ${call.name} -> ${result.error ? 'FAILED' : 'SUCCESS'}` 
          }]);

          toolResponses.push({
            functionResponse: {
              name: call.name,
              id: call.id,
              response: result
            }
          });
        }

        currentHistory.push({ role: 'user', parts: toolResponses });
        loopCount++;
      }
      setHistory(currentHistory);
    } catch (error: any) {
      setMessages(prev => [...prev, { role: 'assistant', content: `Agent Error: ${error.message}` }]);
    } finally {
      setIsProcessing(false);
      setCurrentThought(null);
    }
  };

  const handleExport = () => {
    const data = JSON.stringify({ nodes, edges }, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ux-proto-${new Date().getTime()}.json`;
    a.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (f) => {
      try {
        const data = JSON.parse(f.target?.result as string);
        if (data.nodes) setNodes(data.nodes);
        if (data.edges) setEdges(data.edges);
      } catch (e) { alert("Import failed: Invalid format"); }
    };
    reader.readAsText(file);
  };

  const handleManualAddUX = () => {
    const x = Math.random() * 200 + 100;
    const y = Math.random() * 200 + 100;

    executeAction(CapabilityAddNode.id, {
      label: 'New UX View',
      type: 'ux',
      componentType: 'login-form',
      x,
      y,
      color: 'indigo'
    }, true);
  };

  const handleManualAddTrack = () => {
    executeAction(CapabilityAddTrack.id, {
      label: 'Main System Track',
      x: -500,
      y: 600,
      width: 3000,
      color: 'indigo'
    }, true);
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, currentThought]);

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden font-sans text-slate-200">
      <main className="relative flex-grow h-full overflow-hidden">
        <Canvas 
          nodes={nodes} 
          edges={edges} 
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
        />

        <div className="absolute top-6 left-6 right-6 flex justify-between items-center pointer-events-none">
          <div className="flex items-center space-x-4 pointer-events-auto">
            <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-2 rounded-2xl flex space-x-1 shadow-2xl">
              <button 
                onClick={handleManualAddUX} 
                className="flex items-center space-x-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all font-bold text-xs uppercase tracking-widest shadow-lg shadow-indigo-900/40"
              >
                <Plus size={16} />
                <Layout size={14} />
                <span className="hidden sm:inline">Add UX</span>
              </button>

              <button 
                onClick={handleManualAddTrack} 
                className="flex items-center space-x-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-xl transition-all font-bold text-xs uppercase tracking-widest"
              >
                <Plus size={16} />
                <div className="w-4 h-0.5 bg-indigo-400 rounded-full" />
                <span className="hidden sm:inline">Add Track</span>
              </button>

              <div className="w-px h-8 bg-slate-800 mx-1 self-center" />

              <button onClick={handleExport} className="p-2.5 hover:bg-slate-800 rounded-xl transition-all group text-slate-400 hover:text-blue-400" title="Export Design">
                <Download size={20} />
              </button>
              <label className="p-2.5 hover:bg-slate-800 rounded-xl transition-all group text-slate-400 hover:text-blue-400 cursor-pointer" title="Import Design">
                <Upload size={20} />
                <input type="file" className="hidden" onChange={handleImport} accept=".json" />
              </label>
            </div>

            <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-800 px-5 py-2.5 rounded-2xl flex items-center space-x-3 shadow-2xl">
              <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse" />
              <span className="text-sm font-semibold tracking-wide text-slate-300">
                {nodes.length} Elements
              </span>
            </div>
          </div>
        </div>

        <div className="absolute bottom-6 left-6 bg-slate-900/90 backdrop-blur-xl border border-slate-800 px-4 py-2 rounded-xl pointer-events-none flex items-center space-x-3 text-xs text-slate-400 shadow-xl">
          <Layers size={14} className="text-indigo-400" />
          <span>System Architecture Mode Active</span>
        </div>
      </main>

      <aside className={`transition-all duration-500 ease-[cubic-bezier(0.4,0,0.2,1)] bg-slate-900 border-l border-slate-800 flex flex-col relative z-50 shadow-[0_0_50px_rgba(0,0,0,0.5)] ${isExpanded ? 'fixed inset-0 w-full' : 'w-[450px]'}`}>
        <div className="p-5 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md">
          <div className="flex items-center space-x-4">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-indigo-500 to-blue-600 flex items-center justify-center shadow-lg shadow-indigo-500/20">
              <Brain size={26} className="text-white" />
            </div>
            <div>
              <h2 className="font-bold text-lg text-slate-100 tracking-tight">AI Architect</h2>
              <div className="flex items-center space-x-2">
                <span className={`w-2 h-2 rounded-full ${isProcessing ? 'bg-amber-500 animate-pulse' : 'bg-emerald-500'}`} />
                <span className="text-[10px] font-bold uppercase tracking-widest text-slate-500">{isProcessing ? 'Executing' : 'Safe'}</span>
              </div>
            </div>
          </div>
          <button onClick={() => setIsExpanded(!isExpanded)} className="p-2.5 hover:bg-slate-800 rounded-xl text-slate-400 hover:text-white transition-all">
            {isExpanded ? <Minimize2 size={20} /> : <Maximize2 size={20} />}
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6 scroll-smooth">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] rounded-2xl p-4 transition-all ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none shadow-lg shadow-indigo-900/20' 
                  : msg.role === 'system'
                    ? 'bg-slate-950/50 text-slate-500 text-[10px] font-mono border border-slate-800 py-2'
                    : 'bg-slate-800 text-slate-200 rounded-tl-none border border-slate-700 shadow-sm'
              }`}>
                {msg.role === 'assistant' && msg.isThought && (
                  <div className="flex items-center space-x-2 mb-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest opacity-80">
                    <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full" />
                    <span>Architecting Foundation</span>
                  </div>
                )}
                <div className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</div>
              </div>
            </div>
          ))}
          {currentThought && (
            <div className="flex justify-start">
              <div className="bg-slate-800/50 text-indigo-400 text-xs p-4 rounded-2xl rounded-tl-none flex items-center space-x-4 border border-indigo-900/30 animate-pulse">
                <div className="flex space-x-1">
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                  <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                </div>
                <span className="font-medium">{currentThought}</span>
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-6 border-t border-slate-800 bg-slate-900/80 backdrop-blur-md">
          <div className="relative group">
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage();
                }
              }}
              placeholder="Intent: 'Add a track and put a login form in slot 1'..."
              className="w-full bg-slate-950 border border-slate-800 rounded-2xl py-4 pl-5 pr-16 focus:outline-none focus:ring-2 focus:ring-indigo-600/50 focus:border-indigo-500 transition-all text-slate-200 placeholder-slate-600 resize-none min-h-[100px] shadow-inner"
            />
            <button
              onClick={sendMessage}
              disabled={isProcessing || !userInput.trim()}
              className={`absolute bottom-4 right-4 p-3.5 rounded-xl transition-all shadow-xl ${
                isProcessing || !userInput.trim()
                  ? 'bg-slate-800 text-slate-600'
                  : 'bg-indigo-600 text-white hover:bg-indigo-500 hover:scale-105 active:scale-95'
              }`}
            >
              <Send size={20} />
            </button>
          </div>
        </div>
      </aside>
    </div>
  );
};

export default App;

import { Type } from "@google/genai";
import { AppCapability } from "../types";

export const CapabilitySetActiveTrack: AppCapability = {
  id: 'setActiveTrack',
  name: 'Set Active Track',
  description: 'Designate a specific track ID as the active foundation. New UX components will automatically attach to this track.',
  isExposedToLLM: true,
  parameters: {
    type: Type.OBJECT,
    properties: {
      trackId: { type: Type.STRING, description: 'ID of the track to activate' }
    },
    required: ['trackId']
  }
};

import { CapabilityAddNode } from './addNode';
import { CapabilityUpdateNode } from './updateNode';
import { CapabilityUpdateComponentType } from './updateComponentType';
import { CapabilityDeleteNode } from './deleteNode';
import { CapabilityConnectNodes } from './connectNodes';
import { CapabilityClearCanvas } from './clearCanvas';
import { CapabilityGetCanvasState } from './getCanvasState';
import { CapabilityAddTrack } from './addTrack';
import { CapabilitySetActiveTrack } from './setActiveTrack';

export * from './addNode';
export * from './updateNode';
export * from './updateComponentType';
export * from './deleteNode';
export * from './connectNodes';
export * from './clearCanvas';
export * from './getCanvasState';
export * from './addTrack';
export * from './setActiveTrack';

export const ALL_CAPABILITIES = [
  CapabilityAddNode,
  CapabilityUpdateNode,
  CapabilityUpdateComponentType,
  CapabilityDeleteNode,
  CapabilityConnectNodes,
  CapabilityClearCanvas,
  CapabilityGetCanvasState,
  CapabilityAddTrack,
  CapabilitySetActiveTrack
];

export const getLLMTools = () => ALL_CAPABILITIES
  .filter(c => c.isExposedToLLM)
  .map(c => ({
    name: c.id,
    description: c.description,
    parameters: c.parameters
  }));

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { useNodesState, useEdgesState, addEdge, MarkerType, Connection } from '@xyflow/react';
import { 
  Send, 
  Maximize2, 
  Minimize2, 
  Download, 
  Upload,
  Brain,
  Layers,
  Plus,
  Layout,
  Zap
} from 'lucide-react';
import { 
  Message
} from './types';
import { 
  CapabilityAddNode, 
  CapabilityUpdateNode, 
  CapabilityUpdateComponentType,
  CapabilityDeleteNode, 
  CapabilityConnectNodes, 
  CapabilityClearCanvas, 
  CapabilityGetCanvasState,
  CapabilityAddTrack,
  CapabilitySetActiveTrack
} from './capabilities';
import { SYSTEM_INSTRUCTION, TOOLS } from './constants';
import Canvas from './components/Canvas';

const App: React.FC = () => {
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);
  const [activeTrackId, setActiveTrackId] = useState<string | null>(null);

  const nodesRef = useRef(nodes);
  const edgesRef = useRef(edges);
  useEffect(() => { nodesRef.current = nodes; }, [nodes]);
  useEffect(() => { edgesRef.current = edges; }, [edges]);

  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: "System initialized. I'm ready to architect your UI. Shall we start with a foundation track?" }
  ]);
  const [userInput, setUserInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [currentThought, setCurrentThought] = useState<string | null>(null);
  const [history, setHistory] = useState<any[]>([]);

  const chatEndRef = useRef<HTMLDivElement>(null);

  const getHexColor = (color: string = 'blue') => {
    const palette: Record<string, string> = {
      blue: '#3b82f6',
      green: '#10b981',
      amber: '#f59e0b',
      rose: '#f43f5e',
      purple: '#a855f7',
      slate: '#64748b',
      indigo: '#6366f1'
    };
    return palette[color] || palette.blue;
  };

  const executeAction = useCallback((actionId: string, args: any, isManual: boolean = false) => {
    let result: any;

    switch (actionId) {
      case CapabilitySetActiveTrack.id: {
        const exists = nodesRef.current.some(n => n.id === args.trackId && n.type === 'track');
        if (exists) {
          setActiveTrackId(args.trackId);
          result = { status: 'success', activeTrackId: args.trackId };
        } else {
          result = { error: 'Track not found' };
        }
        break;
      }

      case CapabilityAddTrack.id: {
        const id = `track-${Date.now()}`;
        const newNode = {
          id,
          type: 'track',
          position: { x: args.x ?? 0, y: args.y ?? 0 },
          data: { 
            label: args.label || 'System Foundation',
            width: args.width || 2000,
            color: getHexColor(args.color || 'indigo'),
            executeAction: (id: string, args: any) => executeAction(id, args, true)
          },
        };
        setNodes((nds) => {
          const updated = nds.concat(newNode);
          nodesRef.current = updated;
          return updated;
        });
        setActiveTrackId(id);
        result = { status: 'success', id };
        break;
      }

      case CapabilityAddNode.id: {
        const id = `node-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

        let finalX = args.x ?? 100;
        let finalY = args.y ?? 100;
        let onTrack = false;
        let targetTrackId = args.trackId || activeTrackId;

        // Auto-position if we are attaching to a track
        if (targetTrackId) {
          const trackNode = nodesRef.current.find(n => n.id === targetTrackId);
          if (trackNode) {
            // Calculate slot if not provided
            let slot = args.slot;
            if (slot === undefined) {
              const nodesOnTrack = nodesRef.current.filter(n => n.data.trackId === targetTrackId);
              slot = nodesOnTrack.length;
            }

            const slotWidth = 450; 
            finalX = trackNode.position.x + (slot * slotWidth) + 200; 
            finalY = trackNode.position.y - 450; 
            onTrack = true;
          }
        }

        const newNode = {
          id,
          type: args.type === 'ux' ? 'ux' : (args.type === 'decision' ? 'diamond' : args.type || 'default'),
          position: { x: finalX, y: finalY },
          data: { 
            label: args.label || 'New Step',
            color: getHexColor(args.color),
            componentType: args.componentType,
            onTrack,
            trackId: targetTrackId,
            executeAction: (id: string, args: any) => executeAction(id, args, true)
          },
        };
        setNodes((nds) => {
          const updated = nds.concat(newNode);
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id };
        break;
      }

      case CapabilityUpdateNode.id: {
        setNodes((nds) => {
          const updated = nds.map((node) => {
            if (node.id === args.id) {
              return {
                ...node,
                position: args.x !== undefined || args.y !== undefined 
                  ? { x: args.x ?? node.position.x, y: args.y ?? node.position.y }
                  : node.position,
                data: { 
                  ...node.data, 
                  label: args.label ?? node.data.label,
                  color: args.color ? getHexColor(args.color) : node.data.color
                }
              };
            }
            return node;
          });
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityUpdateComponentType.id: {
        setNodes((nds) => {
          const updated = nds.map((node) => {
            if (node.id === args.id) {
              return {
                ...node,
                data: { 
                  ...node.data, 
                  componentType: args.componentType
                }
              };
            }
            return node;
          });
          nodesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityDeleteNode.id: {
        setNodes((nds) => {
          const updated = nds.filter((n) => n.id !== args.id);
          nodesRef.current = updated;
          return updated;
        });
        setEdges((eds) => {
          const updated = eds.filter((e) => e.source !== args.id && e.target !== args.id);
          edgesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: args.id };
        break;
      }

      case CapabilityConnectNodes.id: {
        const edgeId = `edge-${args.sourceId}-${args.targetId}`;
        const newEdge = {
          id: edgeId,
          source: args.sourceId,
          target: args.targetId,
          label: args.label,
          animated: true,
          style: { stroke: '#6366f1', strokeWidth: 2 },
          markerEnd: { type: MarkerType.ArrowClosed, color: '#6366f1' },
        };
        setEdges((eds) => {
          const updated = addEdge(newEdge, eds);
          edgesRef.current = updated;
          return updated;
        });
        result = { status: 'success', id: edgeId };
        break;
      }

      case CapabilityClearCanvas.id: {
        setNodes([]);
        setEdges([]);
        setActiveTrackId(null);
        nodesRef.current = [];
        edgesRef.current = [];
        result = { status: 'success' };
        break;
      }

      case CapabilityGetCanvasState.id: {
        result = { nodes: nodesRef.current, edges: edgesRef.current, activeTrackId };
        break;
      }

      default:
        throw new Error(`Capability Exception: Unknown Action ID "${actionId}"`);
    }

    if (isManual) {
      setMessages(prev => [...prev, { 
        role: 'system', 
        content: `Audit: ${actionId} executed.` 
      }]);
    }

    return result;
  }, [setNodes, setEdges, activeTrackId]);

  useEffect(() => {
    setNodes((nds) => nds.map(n => ({
      ...n,
      data: { ...n.data, executeAction }
    })));
  }, [executeAction]);

  const onConnect = useCallback((params: Connection) => {
    executeAction(CapabilityConnectNodes.id, {
      sourceId: params.source,
      targetId: params.target
    }, true);
  }, [executeAction]);

  const sendMessage = async () => {
    if (!userInput.trim() || isProcessing) return;

    const currentInput = userInput;
    setUserInput('');
    setMessages(prev => [...prev, { role: 'user', content: currentInput }]);
    setIsProcessing(true);

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const currentHistory = [...history, { role: 'user', parts: [{ text: currentInput }] }];

    try {
      let loopCount = 0;
      const MAX_LOOPS = 6;

      while (loopCount < MAX_LOOPS) {
        setCurrentThought('Architecting Journey...');
        const response: GenerateContentResponse = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: currentHistory,
          config: {
            systemInstruction: SYSTEM_INSTRUCTION,
            tools: [{ functionDeclarations: TOOLS as any }],
          },
        });

        const candidate = response.candidates?.[0];
        if (!candidate) break;

        const parts = candidate.content.parts;
        currentHistory.push({ role: 'model', parts });

        const textOutput = response.text;
        const functionCalls = response.functionCalls || [];

        if (textOutput) {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: textOutput, 
            isThought: functionCalls.length > 0 
          }]);
        }

        if (functionCalls.length === 0) break;

        const toolResponses = [];
        for (const call of functionCalls) {
          setCurrentThought(`System Call: ${call.name}...`);

          let result;
          try {
            result = executeAction(call.name, call.args);
          } catch (err: any) {
            result = { error: err.message };
          }

          toolResponses.push({
            functionResponse: {
              name: call.name,
              id: call.id,
              response: result
            }
          });
        }

        currentHistory.push({ role: 'user', parts: toolResponses });
        loopCount++;
      }
      setHistory(currentHistory);
    } catch (error: any) {
      setMessages(prev => [...prev, { role: 'assistant', content: `Error: ${error.message}` }]);
    } finally {
      setIsProcessing(false);
      setCurrentThought(null);
    }
  };

  const handleExport = () => {
    const data = JSON.stringify({ nodes, edges, activeTrackId }, null, 2);
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `ux-arch-${new Date().getTime()}.json`;
    a.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (f) => {
      try {
        const data = JSON.parse(f.target?.result as string);
        if (data.nodes) setNodes(data.nodes);
        if (data.edges) setEdges(data.edges);
        if (data.activeTrackId) setActiveTrackId(data.activeTrackId);
      } catch (e) { alert("Import failed"); }
    };
    reader.readAsText(file);
  };

  const handleManualAddUX = () => {
    executeAction(CapabilityAddNode.id, {
      label: 'New View',
      type: 'ux',
      componentType: 'login-form',
      color: 'indigo'
    }, true);
  };

  const handleManualAddTrack = () => {
    const y = nodes.length > 0 ? nodes[nodes.length - 1].position.y + 600 : 300;
    executeAction(CapabilityAddTrack.id, {
      label: 'New Foundation',
      x: 0,
      y: y,
      width: 3000,
      color: 'indigo'
    }, true);
  };

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, currentThought]);

  return (
    <div className="flex h-screen w-full bg-slate-950 overflow-hidden font-sans text-slate-200">
      <main className="relative flex-grow h-full overflow-hidden">
        <Canvas 
          nodes={nodes} 
          edges={edges} 
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
        />

        <div className="absolute top-6 left-6 right-6 flex justify-between items-center pointer-events-none">
          <div className="flex items-center space-x-4 pointer-events-auto">
            <div className="bg-slate-900/90 backdrop-blur-xl border border-slate-800 p-2 rounded-2xl flex space-x-1 shadow-2xl">
              <button 
                onClick={handleManualAddTrack} 
                className="flex items-center space-x-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white rounded-xl transition-all font-bold text-[10px] uppercase tracking-widest border border-white/5"
              >
                <Plus size={14} />
                <span>Foundation</span>
              </button>

              <button 
                onClick={handleManualAddUX} 
                disabled={!activeTrackId}
                className="flex items-center space-x-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all font-bold text-[10px] uppercase tracking-widest shadow-lg shadow-indigo-900/40 disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Plus size={14} />
                <span>View</span>
              </button>

              <div className="w-px h-8 bg-slate-800 mx-1 self-center" />

              <button onClick={handleExport} className="p-2.5 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white">
                <Download size={18} />
              </button>
              <label className="p-2.5 hover:bg-slate-800 rounded-xl transition-all text-slate-400 hover:text-white cursor-pointer">
                <Upload size={18} />
                <input type="file" className="hidden" onChange={handleImport} accept=".json" />
              </label>
            </div>

            {activeTrackId && (
              <div className="bg-indigo-600/10 backdrop-blur-xl border border-indigo-500/20 px-4 py-2 rounded-2xl flex items-center space-x-3 shadow-2xl">
                <Zap size={14} className="text-indigo-400 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-400">
                  Active Track: {nodes.find(n => n.id === activeTrackId)?.data.label}
                </span>
              </div>
            )}
          </div>
        </div>
      </main>

      <aside className={`transition-all duration-500 bg-slate-900 border-l border-slate-800 flex flex-col relative z-50 ${isExpanded ? 'fixed inset-0 w-full' : 'w-[400px]'}`}>
        <div className="p-5 border-b border-slate-800 flex justify-between items-center">
          <div className="flex items-center space-x-3">
            <div className="w-10 h-10 rounded-xl bg-indigo-600 flex items-center justify-center shadow-lg shadow-indigo-900/20">
              <Brain size={22} className="text-white" />
            </div>
            <h2 className="font-black text-sm uppercase tracking-[0.2em] text-slate-100">Architect</h2>
          </div>
          <button onClick={() => setIsExpanded(!isExpanded)} className="p-2 hover:bg-slate-800 rounded-lg text-slate-400">
            {isExpanded ? <Minimize2 size={18} /> : <Maximize2 size={18} />}
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-5 space-y-4 scroll-smooth custom-scrollbar">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[90%] rounded-2xl p-4 text-sm leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white' 
                  : msg.role === 'system'
                    ? 'bg-slate-950/50 text-slate-500 text-[9px] font-mono border border-slate-800'
                    : 'bg-slate-800 text-slate-200 border border-slate-700'
              }`}>
                {msg.content}
              </div>
            </div>
          ))}
          {currentThought && (
            <div className="flex justify-start">
              <div className="bg-slate-950/50 text-indigo-400 text-[10px] p-3 rounded-xl border border-indigo-900/30 animate-pulse font-bold uppercase tracking-widest">
                {currentThought}
              </div>
            </div>
          )}
          <div ref={chatEndRef} />
        </div>

        <div className="p-5 border-t border-slate-800 bg-slate-950/50">
          <div className="relative">
            <textarea
              value={userInput}
              onChange={(e) => setUserInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  sendMessage();
                }
              }}
              placeholder="Design intent..."
              className="w-full bg-slate-900 border border-slate-800 rounded-xl py-3 pl-4 pr-12 focus:outline-none focus:ring-1 focus:ring-indigo-500 transition-all text-sm text-slate-200 placeholder-slate-600 resize-none min-h-[80px]"
            />
            <button
              onClick={sendMessage}
              disabled={isProcessing || !userInput.trim()}
              className="absolute bottom-3 right-3 p-2 rounded-lg bg-indigo-600 text-white disabled:opacity-50"
            >
              <Send size={16} />
            </button>
          </div>
        </div>
      </aside>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Handle, Position } from '@xyflow/react';
import { Search, ChevronDown, Check, Maximize2, ExternalLink } from 'lucide-react';
import { UX_COMPONENTS, UX_COMPONENT_KEYS } from './ux/registry';
import { CapabilityUpdateComponentType } from '../capabilities/index';
import UXModal from './UXModal';

// Autocomplete Component for UX nodes
const ComponentAutocomplete = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [query, setQuery] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  const options = UX_COMPONENT_KEYS;
  const filteredOptions = options.filter(opt => 
    opt.toLowerCase().includes(query.toLowerCase())
  );

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <div ref={containerRef} className="relative w-40 group pointer-events-auto">
      <div 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center justify-between bg-slate-900/90 backdrop-blur-md text-white px-2 py-1.5 rounded-lg shadow-lg cursor-pointer transition-all border border-slate-700 hover:border-blue-500"
      >
        <span className="text-[9px] font-bold uppercase tracking-wider truncate mr-1">
          {value || 'Select Component'}
        </span>
        <ChevronDown size={12} className={`transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} />
      </div>

      {isOpen && (
        <div className="absolute bottom-full left-0 mb-2 w-full bg-slate-900 border border-slate-700 rounded-xl shadow-2xl z-[100] overflow-hidden animate-in fade-in slide-in-from-bottom-2 duration-200">
          <div className="p-2 border-b border-slate-800 flex items-center bg-slate-950/50">
            <Search size={10} className="text-slate-500 mr-2" />
            <input 
              autoFocus
              className="bg-transparent border-none outline-none text-[10px] text-slate-200 w-full placeholder-slate-600"
              placeholder="Search..."
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              onClick={(e) => e.stopPropagation()}
            />
          </div>
          <div className="max-h-40 overflow-y-auto p-1 custom-scrollbar">
            {filteredOptions.length > 0 ? (
              filteredOptions.map((opt) => (
                <div 
                  key={opt}
                  onClick={(e) => {
                    e.stopPropagation();
                    onChange(opt);
                    setIsOpen(false);
                    setQuery('');
                  }}
                  className={`flex items-center justify-between px-2 py-1.5 rounded-lg text-[9px] font-medium cursor-pointer transition-colors ${
                    value === opt 
                      ? 'bg-blue-600/20 text-blue-400' 
                      : 'text-slate-400 hover:bg-slate-800 hover:text-white'
                  }`}
                >
                  <span>{opt}</span>
                  {value === opt && <Check size={8} />}
                </div>
              ))
            ) : (
              <div className="px-2 py-3 text-[9px] text-slate-600 italic text-center">
                No results
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export const UXNode = ({ id, data, selected }: any) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [scale, setScale] = useState(0.2); 
  const componentRef = useRef<HTMLDivElement>(null);
  const Component = UX_COMPONENTS[data.componentType];

  const previewWidth = 260;
  const previewHeight = 320;
  const paddingBuffer = 40;

  const updateScale = useCallback(() => {
    if (componentRef.current) {
      const { scrollWidth, scrollHeight } = componentRef.current;
      if (scrollWidth > 1 && scrollHeight > 1) {
        const scaleW = (previewWidth - paddingBuffer) / scrollWidth;
        const scaleH = (previewHeight - paddingBuffer) / scrollHeight;
        const newScale = Math.min(scaleW, scaleH);
        setScale(newScale);
      }
    }
  }, [previewWidth, previewHeight, paddingBuffer]);

  useEffect(() => {
    if (!componentRef.current) return;
    const observer = new ResizeObserver(() => requestAnimationFrame(updateScale));
    observer.observe(componentRef.current);
    updateScale();
    return () => observer.disconnect();
  }, [updateScale, data.componentType, data.componentProps]);

  const handleTypeChange = (newType: string) => {
    if (data.executeAction) {
      data.executeAction(CapabilityUpdateComponentType.id, { id, componentType: newType });
    }
  };

  const nodeColor = data.color || '#6366f1';

  return (
    <div className={`relative group transition-all duration-300 ${selected ? 'ring-4 ring-blue-500/50 rounded-2xl' : ''}`}>

      {/* ARCHITECTURAL STEM (If attached to track) */}
      {data.onTrack && (
        <div className="absolute top-[320px] left-1/2 -translate-x-1/2 w-[2px] h-[130px] pointer-events-none flex flex-col items-center z-[-1]">
          {/* Vertical Beam with pulsing gradient */}
          <div 
            className="w-full h-full animate-beam-pulse"
            style={{ 
              background: `linear-gradient(to bottom, ${nodeColor}BB, ${nodeColor}22)`,
            }} 
          />

          {/* THE GLOWING POINT (Aligned to Track) */}
          <div className="absolute bottom-0 flex items-center justify-center">
            {/* Inner high-intensity spark */}
            <div className="w-1.5 h-1.5 bg-white rounded-full shadow-[0_0_15px_white] z-10" />

            {/* Mid-glow pulse */}
            <div 
              className="absolute w-6 h-6 rounded-full opacity-50 blur-md animate-ping"
              style={{ backgroundColor: nodeColor }}
            />

            {/* Static outer glow */}
            <div 
              className="absolute w-4 h-4 rounded-full blur-sm"
              style={{ backgroundColor: nodeColor, boxShadow: `0 0 20px ${nodeColor}` }}
            />
          </div>
        </div>
      )}

      {/* Top UI Overlay */}
      <div className="absolute -top-10 left-0 flex items-center justify-between w-full px-0">
        <ComponentAutocomplete 
          value={data.componentType}
          onChange={handleTypeChange}
        />
        <div className="flex space-x-1.5 pointer-events-auto">
           <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-slate-900/90 backdrop-blur-md border border-slate-700 p-1.5 rounded-lg text-slate-400 hover:text-white hover:border-blue-500 transition-all shadow-xl"
            title="Expand Preview"
          >
            <Maximize2 size={14} />
          </button>
        </div>
      </div>

      <Handle type="target" position={Position.Left} className="!bg-blue-500 !w-3 !h-3 !border-slate-900 !-left-1.5" />

      <div 
        className="relative bg-slate-100 rounded-xl overflow-hidden border border-slate-800 shadow-2xl transition-all group-hover:border-slate-600 flex items-center justify-center"
        style={{ width: previewWidth, height: previewHeight }}
      >
        <div 
          className="transition-transform duration-500 ease-out origin-center flex items-center justify-center" 
          style={{ transform: `scale(${scale})` }}
        >
          <div ref={componentRef} className="inline-block">
            {Component ? (
               <div className="pointer-events-none flex items-center justify-center">
                  <Component {...data.componentProps} />
               </div>
            ) : (
              <div className="p-12 text-slate-400 italic text-[10px] text-center uppercase tracking-[0.3em] font-black w-[300px]">
                Architecting View...
              </div>
            )}
          </div>
        </div>

        <div className="absolute inset-0 bg-transparent z-10" />

        <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity z-20 pointer-events-none">
          <button 
            onClick={(e) => { e.stopPropagation(); setIsModalOpen(true); }}
            className="pointer-events-auto bg-indigo-600 hover:bg-indigo-500 text-white px-3 py-1.5 rounded-full shadow-2xl font-bold text-[9px] uppercase tracking-widest flex items-center space-x-1.5 transform translate-y-2 group-hover:translate-y-0 transition-all"
          >
            <ExternalLink size={10} />
            <span>Interactive Scale</span>
          </button>
        </div>
      </div>

      <Handle type="source" position={Position.Right} className="!bg-blue-500 !w-3 !h-3 !border-slate-900 !-right-1.5" />

      <div className="mt-1.5 flex items-center justify-between px-1">
        <span className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter truncate max-w-[100px]">{data.label}</span>
        <span className="text-[8px] font-mono text-slate-800">{id}</span>
      </div>

      <UXModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        componentType={data.componentType} 
        id={id} 
        componentProps={data.componentProps} 
      />

      <style>{`
        @keyframes beam-pulse {
          0%, 100% { opacity: 0.6; }
          50% { opacity: 1; }
        }
        .animate-beam-pulse {
          animation: beam-pulse 3s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

export default UXNode;
